const acao = $input.item.json.body.acao || 'UNKNOWN';
const allowedActions = [
  'VALIDAR_JSON',
  'GERAR_FIXED_JSON',
  'FORCAR_ACTIVE_FALSE',
  'GERAR_RELATORIO',
  'CRIAR_BACKUP',
  'VALIDAR_KILLCRITIC'
];
const forbiddenActions = [
  'DELETE_WORKFLOW',
  'ACTIVATE_WORKFLOW',
  'PUBLISH_SOCIAL',
  'SEND_WHATSAPP',
  'CHANGE_CREDENTIAL',
  'RESTART_CONTAINER'
];

let permitido = false;
let precisa_aprovacao = false;
let motivo = '';

if (forbiddenActions.includes(acao)) {
  permitido = false;
  motivo = 'Ação expressamente proibida pelo protocolo KILLCRITIC/DL NEXUS V3.';
} else if (allowedActions.includes(acao)) {
  permitido = true;
  motivo = 'Ação segura (não destrutiva) permitida.';
} else {
  permitido = false;
  precisa_aprovacao = true;
  motivo = 'Ação não mapeada, requer aprovação operacional.';
}

return [
  {
    json: {
      status: permitido ? 'success' : 'blocked',
      acao: acao,
      permitido: permitido,
      executado: permitido,
      precisa_aprovacao: precisa_aprovacao,
      motivo: motivo
    }
  }
];
